'use strict';

/**
 * createRateLimiter — TRUE sliding window rate limiting middleware for Express.
 *
 * Unlike a fixed-window limiter (which resets a counter at fixed interval
 * boundaries and allows bursts of up to 2x the limit around the boundary),
 * this stores the timestamp of every request per client and, on each new
 * request, discards any timestamp older than `windowMs` before counting.
 * The window therefore slides continuously with "now".
 *
 * @param {Object}   [options]
 * @param {number}   [options.windowMs=60000]          Window size in ms.
 * @param {number}   [options.maxRequests=100]         Max requests per window.
 * @param {Function} [options.keyGenerator]            (req) => string. Defaults to req.ip.
 * @param {number}   [options.cleanupIntervalMs=60000] Sweep interval for idle IPs.
 * @returns {Function} Express middleware with a `.close()` method that stops
 *                     the cleanup timer.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    keyGenerator = (req) => req.ip,
    cleanupIntervalMs = 60000,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isFinite(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive number');
  }

  // Map<clientKey, number[]> — ascending arrays of request timestamps (ms).
  const hits = new Map();

  /**
   * Drop every timestamp at or before `cutoff`. Timestamps are pushed in
   * chronological order, so expired entries form a prefix we slice off once.
   */
  function pruneExpired(timestamps, cutoff) {
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= cutoff) {
      i++;
    }
    return i > 0 ? timestamps.slice(i) : timestamps;
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const cutoff = now - windowMs;
    const key = keyGenerator(req);

    // Sliding window step 1: remove all timestamps older than the window.
    let timestamps = pruneExpired(hits.get(key) || [], cutoff);

    // Sliding window step 2: count what remains.
    if (timestamps.length >= maxRequests) {
      // Over the limit — reject. A slot frees when the OLDEST surviving
      // timestamp falls out of the window.
      const oldest = timestamps[0];
      const resetMs = oldest + windowMs;
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      // Persist the pruned array so memory does not grow unbounded.
      hits.set(key, timestamps);

      res.setHeader('Retry-After', String(retryAfterSec));
      res.setHeader('X-RateLimit-Limit', String(maxRequests));
      res.setHeader('X-RateLimit-Remaining', '0');
      res.setHeader('X-RateLimit-Reset', String(Math.ceil(resetMs / 1000)));

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next().
    }

    // Sliding window step 3: under the limit — record this request and allow.
    timestamps.push(now);
    hits.set(key, timestamps);

    const remaining = maxRequests - timestamps.length;
    // Reset = when the oldest in-window request expires (a slot frees).
    const resetMs = timestamps[0] + windowMs;

    res.setHeader('X-RateLimit-Limit', String(maxRequests));
    res.setHeader('X-RateLimit-Remaining', String(remaining));
    res.setHeader('X-RateLimit-Reset', String(Math.ceil(resetMs / 1000)));

    next();
  };

  // ---- Memory management -------------------------------------------------
  // Periodically sweep IPs with no requests within the last window.
  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      const live = pruneExpired(timestamps, cutoff);
      if (live.length === 0) {
        hits.delete(key);
      } else if (live.length !== timestamps.length) {
        hits.set(key, live);
      }
    }
  }, cleanupIntervalMs);

  // Don't let the cleanup timer keep the Node.js process alive.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  /**
   * Stop the cleanup interval. Call on graceful shutdown (or in tests) to
   * release the timer. The middleware still works afterward; it just stops
   * sweeping idle entries.
   */
  middleware.close = function close() {
    clearInterval(cleanupTimer);
  };

  return middleware;
}

module.exports = createRateLimiter;
module.exports.createRateLimiter = createRateLimiter;
```

