/**
 * Sliding Window Rate Limiter Middleware for Express.js
 * ======================================================
 * A TRUE sliding window algorithm. Rather than resetting a counter on a fixed
 * clock boundary, each request's exact timestamp is recorded per IP. On every
 * incoming request the window is re-evaluated from "now", so a burst at
 * 00:00:59 does NOT fully reset at 00:01:00 — those timestamps stay in the
 * window until they individually age out 60 s after they arrived.
 *
 * ─── NOTE: req.ip behind a reverse proxy ──────────────────────────────────────
 * Express derives req.ip from the connecting socket by default. When your app
 * runs behind Nginx, AWS ELB, Cloudflare, or any other proxy, the real client
 * address is forwarded in the X-Forwarded-For header, and req.ip resolves to
 * the *proxy's* address instead — meaning every visitor shares one bucket.
 *
 * Fix: tell Express how far to trust your proxy chain:
 *
 *   app.set('trust proxy', 1);          // trust first hop (Nginx on same host)
 *   app.set('trust proxy', 'loopback'); // trust loopback addresses only
 *   app.set('trust proxy', true);       // trust all hops (use with caution)
 *
 * See https://expressjs.com/en/guide/behind-proxies.html for full details.
 * ──────────────────────────────────────────────────────────────────────────────
 */

'use strict';

/**
 * Create a sliding-window rate limiter.
 *
 * @param {object}  [options]
 * @param {number}  [options.windowMs=60000]   Window duration in milliseconds.
 * @param {number}  [options.maxRequests=100]  Max requests allowed per window.
 *
 * @returns {{ middleware: import('express').RequestHandler, close: () => void }}
 *   - `middleware` — Express middleware to mount with app.use() / router.use().
 *   - `close()`    — Stops the background cleanup timer; call on graceful shutdown.
 */
function createRateLimiter(options = {}) {
  // ── Configuration ────────────────────────────────────────────────────────────
  const windowMs    = typeof options.windowMs    === 'number' ? options.windowMs    : 60_000;
  const maxRequests = typeof options.maxRequests === 'number' ? options.maxRequests : 100;

  if (windowMs    <= 0) throw new RangeError('windowMs must be a positive number');
  if (maxRequests <= 0) throw new RangeError('maxRequests must be a positive number');

  // ── In-memory store ──────────────────────────────────────────────────────────
  // Map<ip: string, timestamps: number[]>
  //
  // The array for each IP holds the epoch-ms timestamps of every request that
  // still falls inside the current sliding window.  Timestamps are kept in
  // insertion order (oldest first), which makes windowed eviction a single
  // filter pass — no sorting required.
  const store = new Map();

  // ── Background cleanup ───────────────────────────────────────────────────────
  // Periodically removes IPs whose entire timestamp log has slid out of the
  // window.  Without this, every IP that ever sent a request accumulates in the
  // Map for the lifetime of the process.
  //
  // The interval fires every 60 s regardless of windowMs so that short-window
  // limiters (e.g. windowMs: 5_000) still reclaim memory promptly.
  const cleanupIntervalId = setInterval(() => {
    const cutoff = Date.now() - windowMs;

    for (const [ip, timestamps] of store) {
      const fresh = timestamps.filter(t => t > cutoff);

      if (fresh.length === 0) {
        store.delete(ip);          // no recent activity — evict entirely
      } else {
        store.set(ip, fresh);      // trim stale head of the list
      }
    }
  }, 60_000);

  // unref() prevents this timer from keeping the Node.js event loop alive once
  // all other I/O (servers, sockets, etc.) has finished — the process exits
  // naturally without needing an explicit close() call in the common case.
  if (typeof cleanupIntervalId.unref === 'function') {
    cleanupIntervalId.unref();
  }

  // ── Middleware ───────────────────────────────────────────────────────────────
  function middleware(req, res, next) {
    const now = Date.now();

    // Resolve the client identifier, with a fallback chain for environments
    // where req.ip may be undefined (unit tests, non-HTTP transports, etc.).
    const ip =
      req.ip ??
      req.socket?.remoteAddress ??
      req.connection?.remoteAddress ??
      'unknown';

    // 1. Load existing timestamps for this IP (empty array for first visit).
    let timestamps = store.get(ip) ?? [];

    // 2. Slide the window: drop any timestamp that has aged past windowMs.
    //    This is the core of the true sliding window — we don't reset on a
    //    clock boundary; we re-evaluate the window on every single request.
    const windowStart = now - windowMs;
    timestamps = timestamps.filter(t => t > windowStart);

    // 3a. REJECT — at or over the limit.
    if (timestamps.length >= maxRequests) {
      // The next slot opens when the oldest surviving timestamp slides out.
      const oldestTs    = timestamps[0];                    // earliest in window
      const retryAfterS = Math.ceil(((oldestTs + windowMs) - now) / 1000);

      // Persist the trimmed list so the cleanup pass has accurate data even
      // for IPs that are actively at the ceiling.
      store.set(ip, timestamps);

      res.set('Retry-After', String(retryAfterS));

      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterS,
      });
    }

    // 3b. ALLOW — admit the request by appending its timestamp.
    timestamps.push(now);
    store.set(ip, timestamps);

    // Set informational headers:
    //
    //   X-RateLimit-Limit     : the configured ceiling for this limiter
    //   X-RateLimit-Remaining : remaining requests allowed right now
    //   X-RateLimit-Reset     : Unix epoch second when the *oldest* request in
    //                           the window slides out — the earliest moment a
    //                           fresh slot is guaranteed to open.  In a true
    //                           sliding window this advances continuously, not
    //                           on a fixed clock tick.
    const resetEpochS = Math.ceil((timestamps[0] + windowMs) / 1000);

    res.set({
      'X-RateLimit-Limit':     String(maxRequests),
      'X-RateLimit-Remaining': String(maxRequests - timestamps.length),
      'X-RateLimit-Reset':     String(resetEpochS),
    });

    next();
  }

  // ── Lifecycle ────────────────────────────────────────────────────────────────
  /**
   * Stop the background cleanup timer.
   *
   * unref() handles the common case automatically, but call close() explicitly
   * during graceful shutdown when you need deterministic timer teardown (e.g.
   * in test suites or runtimes that don't support unref()).
   *
   * @example
   *   process.on('SIGTERM', () => { limiter.close(); server.close(); });
   */
  function close() {
    clearInterval(cleanupIntervalId);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
```

