## `app.js` — Usage Example

```js
const express = require('express');
const { createRateLimiter } = require('./rateLimiter');

const app = express();

// ── Proxy trust ──────────────────────────────────────────────────────────────
// Required when running behind Nginx, a load balancer, or any reverse proxy so
// that req.ip reflects the real client address from X-Forwarded-For rather than
// the proxy's own address.  Adjust the value to match your deployment topology.
app.set('trust proxy', 1);

// ── General API limiter: 100 req / 60-second sliding window ─────────────────
const apiLimiter = createRateLimiter({
  windowMs:    60_000,   // 1 minute
  maxRequests: 100,
});

// ── Stricter limiter for auth routes ─────────────────────────────────────────
const authLimiter = createRateLimiter({
  windowMs:    15 * 60_000,  // 15 minutes
  maxRequests: 10,
});

// Mount limiters before route handlers so they run first.
// Order matters: the specific /api/auth limiter must be registered BEFORE
// the broader /api limiter, otherwise the broader one fires first.
app.use('/api/auth', authLimiter.middleware);
app.use('/api',      apiLimiter.middleware);

// ── Routes ───────────────────────────────────────────────────────────────────
app.post('/api/auth/login', (req, res) => {
  res.json({ token: 'example' });
});

app.get('/api/data', (req, res) => {
  res.json({ message: 'Hello!' });
});

// ── Server ───────────────────────────────────────────────────────────────────
const server = app.listen(3000, () => {
  console.log('Listening on http://localhost:3000');
});

// Graceful shutdown: stop cleanup timers so the process exits cleanly.
// unref() already handles the common case; this is for test suites and
// environments where unref() is unavailable.
function shutdown() {
  apiLimiter.close();
  authLimiter.close();
  server.close(() => process.exit(0));
}
process.on('SIGTERM', shutdown);
process.on('SIGINT',  shutdown);
```

